1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type Step = {
9	  op: string;
10	  items?: Item[];
11	};
12	
13	export type Scenario = {
14	  customer: { yearsWithMHPCO: number };
15	  steps: Step[];
16	};
17	
18	export type ScenarioResult = {
19	  results: unknown[];
20	};
21	
22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_SURCHARGE = 0.1;
24	
25	const ITEM_BASE_PREMIUM: Record<string, number> = {
26	  sword: 100,
27	  rune: 25,
28	};
29	
30	const COMPONENT_TYPES = new Set(["rune"]);
31	const COMPONENT_BLOCK_SIZE = 3;
32	const COMPONENT_BLOCK_PREMIUM = 60;
33	
34	const groupCountsByType = (items: Item[]): Map<string, number> => {
35	  const counts = new Map<string, number>();
36	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
37	  return counts;
38	};
39	
40	const baseForGroup = (type: string, count: number): number => {
41	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
42	  return count * ITEM_BASE_PREMIUM[type];
43	};
44	
45	const calculatePremium = (items: Item[]): number => {
46	  const counts = groupCountsByType(items);
47	  let base = 0;
48	  for (const [type, count] of counts) base += baseForGroup(type, count);
49	  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE;
50	  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
51	};
52	
53	export const runScenario = (scenario: Scenario): ScenarioResult => {
54	  const results = scenario.steps.map((step) => ({
55	    premium: calculatePremium(step.items ?? []),
56	  }));
57	  return { results };
58	};
